INSERT INTO `faq` (`id`, `question`, `answer`, `sort_order`, `status`, `created_at`, `updated_at`, `is_deleted`) VALUES
(1, '资源是否支持二次编辑？', '大部分资料包提供可编辑版本，页面会明确标注是否支持修改。老师可先看预览样张，再确认是否适合本班使用。', 100, 1, '2026-04-03 08:30:00', '2026-04-03 08:30:00', 0),
(2, '资源如何交付？', '本站不做站内支付和在线下载，确认需求后通过微信沟通交付。管理员会根据资源码快速匹配资料并发送网盘信息。', 90, 1, '2026-04-03 08:30:00', '2026-04-03 08:30:00', 0),
(3, '如何快速咨询？', '建议先看预览，再复制资源码。加微信时直接发送资源码，可更快为你匹配和交付。', 80, 1, '2026-04-03 08:30:00', '2026-04-03 08:30:00', 0),
(4, '如果资料丢失，是否支持补发？', '支持补发。请通过微信说明资源码或大致购买时间，我们核对后可安排补发。', 70, 1, '2026-04-03 08:30:00', '2026-04-03 08:30:00', 0),
(5, '这些资料适合哪些年级？', '每个资源详情页都会标注适用年级和适用场景。通用类资料通常适合一年级到六年级按需微调使用。', 60, 1, '2026-04-03 08:30:00', '2026-04-03 08:30:00', 0),
(6, '是否可以先看预览再决定？', '可以。本站重点资源都提供预览图，建议老师先浏览样张，确认风格和内容结构后再加微信咨询。', 50, 1, '2026-04-03 08:30:00', '2026-04-03 08:30:00', 0);
