(3, 'wechat_official', '公众号', 'wechat_official', '公众号文章和菜单页导流。', 80, 1, '2026-04-03 08:30:00', '2026-04-03 08:30:00', 0),
(4, 'other', '其他', 'other', '朋友圈、社群、转介绍等其他来源。', 70, 1, '2026-04-03 08:30:00', '2026-04-03 08:30:00', 0);
INSERT INTO `resource` (`id`, `resource_code`, `title`, `slug`, `category_id`, `source_id`, `summary`, `cover_image`, `display_price`, `grade`, `scene`, `content_items_json`, `description_html`, `usage_notice`, `delivery_notice`, `search_keywords`, `authorization_status_snapshot`, `preview_count`, `content_item_count`, `status`, `is_recommended`, `view_count`, `consult_count`, `sort_order`, `publish_time`, `created_at`, `updated_at`, `is_deleted`) VALUES
(1, 'RES-BZR-20260403-0001', '小学开学第一课课件教案包', 'primary-school-first-lesson-kit', 1, 1, '适合新学期开学第一周直接使用的完整资料包，覆盖班级常规、安全提醒和师生破冰。', 'https://placehold.co/1200x760/png?text=resource-1-cover', 39.90, '一年级-六年级', '开学第一课', '["开学第一课PPT","配套教案","教师开场词","课堂互动环节","班级常规提醒页"]', '<p>这是一套面向小学班主任和任课老师的开学第一课备课资料包，适合新学期第一周直接上课使用。</p><p>资料围绕班级秩序建立、学习习惯提醒、师生破冰和安全教育导入整理，强调先看预览，再加微信发送资源码快速咨询。</p>', '建议先浏览预览样张，再结合班级人数、班规重点和学生年龄段进行微调后使用。', '本站不做在线支付，请先看预览，再加微信发送资源码确认需求，确认后通过微信沟通交付网盘信息。', '小学,开学,第一课,班主任,课件,教案,资料包,资源码', 'APPROVED', 3, 5, 1, 1, 286, 38, 130, '2026-04-03 09:10:00', '2026-04-03 09:10:00', '2026-04-03 09:10:00', 0),
(2, 'RES-JZH-20260403-0001', '小学家长会 PPT + 发言稿通用包', 'parent-meeting-ppt-speech-kit', 2, 2, '适合班主任召开新学期、阶段总结、期末反馈等场景的家长会资料包。', 'https://placehold.co/1200x760/png?text=resource-2-cover', 49.00, '一年级-六年级', '家长会', '["家长会PPT","班主任发言稿","家校配合建议页","班级情况汇报模板","会后沟通要点"]', '<p>这套资料围绕小学家长会高频使用场景整理，兼顾班级展示、习惯沟通和家校协同三类核心内容。</p><p>资料结构清晰，适合先看预览样张，再带着资源码到微信侧快速确认是否适合本班使用。</p>', '使用前建议先补充本班成绩、行为习惯和班级活动照片，再统一调整班级名称和落款。', '本站不做在线支付，确认需求后通过微信沟通交付；加微信时发送资源码，可更快匹配发货。', '小学,家长会,PPT,发言稿,家校沟通,班主任,通用包', 'APPROVED', 3, 5, 1, 1, 318, 46, 128, '2026-04-03 09:20:00', '2026-04-03 09:20:00', '2026-04-03 09:20:00', 0),
(3, 'RES-BHZ-20260403-0001', '小学生安全教育主题班会全套包', 'student-safety-class-meeting-kit', 3, 1, '围绕校园安全、课间安全、交通安全等内容整理的主题班会整套资料。', 'https://placehold.co/1200x760/png?text=resource-3-cover', 36.00, '一年级-六年级', '主题班会', '["主题班会PPT","班会流程教案","案例讨论页","课堂互动问答","课后提醒话术"]', '<p>资料聚焦小学阶段常见安全教育主题，帮助老师在有限课时内完成重点提醒和互动引导。</p><p>整套内容适合常规班会，也适合作为学校安全教育周的班级落实资料。</p>', '建议根据年级调整案例难度，低年级可多用图片说明，高年级可增加讨论和承诺环节。', '本站不做在线支付，建议先看预览图，再加微信发送资源码确认内容和交付方式。', '小学,安全教育,主题班会,校园安全,交通安全,班会,资料包', 'APPROVED', 3, 5, 1, 1, 256, 31, 126, '2026-04-03 09:30:00', '2026-04-03 09:30:00', '2026-04-03 09:30:00', 0),
(4, 'RES-BHZ-20260403-0002', '防校园欺凌主题班会资源包', 'anti-bullying-class-meeting-kit', 3, 1, '适合开展校园欺凌预防教育、规则教育和同伴相处引导的班会资料。', 'https://placehold.co/1200x760/png?text=resource-4-cover', 29.90, '三年级-六年级', '主题班会', '["防欺凌PPT","案例讨论题","班会教案","学生承诺卡文案","课后提醒页"]', '<p>这套资料面向中高年级班会场景，重点帮助老师解释什么是校园欺凌、如何识别以及如何正确求助。</p><p>资料强调规则意识和同伴边界感，适合做成一次完整班会，也适合拆分到德育课中使用。</p>', '建议配合学校德育制度和班级公约使用，班会结束后可让学生再次确认求助渠道。', '本站不做站内支付，确认需求后通过微信沟通交付；建议加微信时直接发送资源码。', '校园欺凌,班会,安全教育,德育,规则教育,中高年级', 'APPROVED', 3, 5, 1, 0, 227, 19, 124, '2026-04-03 09:40:00', '2026-04-03 09:40:00', '2026-04-03 09:40:00', 0),
(5, 'RES-BHZ-20260403-0003', '心理健康与情绪管理班会包', 'mental-health-emotion-class-kit', 3, 1, '适合围绕情绪识别、表达方式、同伴支持开展班会的资料包。', 'https://placehold.co/1200x760/png?text=resource-5-cover', 32.00, '三年级-六年级', '主题班会', '["情绪管理PPT","班会教案","情绪卡片文案","案例讨论页","教师引导话术"]', '<p>资料围绕小学中高年级常见情绪场景整理，帮助老师用更温和、可理解的方式开展心理健康启蒙。</p><p>内容强调情绪识别、表达和同伴支持，适合日常德育班会、心理健康周或专题教育使用。</p>', '建议老师提前熟悉案例内容，班会中多使用开放式提问，让学生更自然地表达自己的感受。', '本站不做在线支付，请先查看预览样张，确认风格和适用场景后再通过微信沟通交付。', '心理健康,情绪管理,班会,德育,小学,中高年级', 'APPROVED', 3, 5, 1, 0, 188, 14, 120, '2026-04-03 09:50:00', '2026-04-03 09:50:00', '2026-04-03 09:50:00', 0),
(6, 'RES-BHZ-20260403-0004', '防溺水安全教育专题包', 'water-safety-education-kit', 3, 2, '适合夏季前后开展防溺水提醒、案例警示和家校协同教育的专题资料。', 'https://placehold.co/1200x760/png?text=resource-6-cover', 33.00, '一年级-六年级', '安全教育', '["防溺水PPT","专题教案","家长提醒文案","案例警示页","安全口诀页"]', '<p>这套资料围绕小学阶段高频的防溺水教育需求整理，兼顾学生课堂提醒与家长配合提醒两个方向。</p><p>适合假期前班会、学校专题活动或安全教育周使用。</p>', '建议根据学校所在地实际水域情况补充本地提醒内容，家校沟通时同步发送重点注意事项。', '本站不做在线支付，资料确认后通过微信沟通交付；请先复制资源码再咨询。', '防溺水,安全教育,班会,假期安全,家校提醒,小学', 'APPROVED', 3, 5, 1, 1, 241, 27, 118, '2026-04-03 10:00:00', '2026-04-03 10:00:00', '2026-04-03 10:00:00', 0),
(7, 'RES-FXK-20260403-0001', '小学期中复习动员班会包', 'midterm-review-motivation-class-kit', 5, 1, '适合期中阶段用于目标设定、复习规划和学习状态调整的班会资料。', 'https://placehold.co/1200x760/png?text=resource-7-cover', 28.00, '三年级-六年级', '期中复习', '["复习动员PPT","班会教案","复习计划表","目标打卡页","鼓励话术文案"]', '<p>资料聚焦期中复习前的学习状态调整，帮助老师在班会中明确节奏、统一目标并提升学生投入度。</p><p>适合复习启动阶段直接使用，也适合班主任做阶段性动员。</p>', '建议结合班级近期作业完成情况和考试安排，替换成更符合本班节奏的复习提醒内容。', '本站不做站内支付，确认需求后通过微信沟通交付；发送资源码可更快匹配复习类资料。', '期中,复习,动员,班会,学习状态,复习课', 'APPROVED', 3, 5, 1, 0, 165, 12, 116, '2026-04-03 10:10:00', '2026-04-03 10:10:00', '2026-04-03 10:10:00', 0),
(8, 'RES-JZH-20260403-0002', '小学期末冲刺家长会资料包', 'final-review-parent-meeting-kit', 2, 2, '适合期末阶段向家长说明复习安排、习惯配合和假期衔接事项的资料包。', 'https://placehold.co/1200x760/png?text=resource-8-cover', 45.00, '一年级-六年级', '期末复习', '["期末家长会PPT","发言稿","复习建议清单","家长配合提醒","假期衔接说明页"]', '<p>这套资料适合期末前后的家长会场景，重点帮助老师清晰传达复习安排、学生表现和家长配合重点。</p><p>资料结构兼顾成绩沟通与情绪支持，适合需要稳妥表达的老师使用。</p>', '建议老师提前补充班级近期表现数据和复习时间安排，再统一替换学校名称与教师署名。', '本站不做在线支付，确认需求后通过微信沟通交付；请先看预览，再带资源码咨询。', '期末,家长会,复习,家校沟通,班主任,资料包', 'APPROVED', 3, 5, 1, 1, 212, 24, 114, '2026-04-03 10:20:00', '2026-04-03 10:20:00', '2026-04-03 10:20:00', 0),
(9, 'RES-GKK-20260403-0001', '小学语文公开课通用模板包', 'chinese-open-class-template-kit', 4, 2, '适合小学语文公开课展示、赛课和教研交流使用的通用课件模板资料。', 'https://placehold.co/1200x760/png?text=resource-9-cover', 59.00, '一年级-六年级', '公开课', '["语文公开课PPT模板","教学流程页","课堂活动页","板书设计示例","说课提纲"]', '<p>资料围绕小学语文公开课常见结构整理，适合用于教研展示、赛课准备或公开课打磨阶段。</p><p>模板页布局规范，方便老师快速替换课文内容进入正式备课。</p>', '使用前建议先确定课型和课文内容，再按教学目标替换模板页，避免页面过多影响课堂节奏。', '本站不做在线支付，确认需求后通过微信沟通交付；公开课资料建议先看预览后咨询。', '语文,公开课,模板,赛课,说课,教研,课件', 'APPROVED', 3, 5, 1, 1, 369, 52, 112, '2026-04-03 10:30:00', '2026-04-03 10:30:00', '2026-04-03 10:30:00', 0),
(10, 'RES-GKK-20260403-0002', '小学数学公开课通用模板包', 'math-open-class-template-kit', 4, 2, '适合小学数学公开课、教研展示和课堂结构梳理的通用模板资料。', 'https://placehold.co/1200x760/png?text=resource-10-cover', 59.00, '一年级-六年级', '公开课', '["数学公开课PPT模板","情境导入页","探究活动页","练习反馈页","说课结构提纲"]', '<p>资料重点服务小学数学公开课准备，帮助老师在导入、探究、练习和总结几个关键环节快速搭建结构。</p><p>模板适合赛课前反复修改，也适合平时教研组内统一课件风格使用。</p>', '建议根据课题内容删减或合并部分模板页，保证公开课页面数量和课堂时长匹配。', '本站不做在线支付，确认需求后通过微信沟通交付；复制资源码后再咨询更高效。', '数学,公开课,模板,探究活动,练习反馈,赛课', 'APPROVED', 3, 5, 1, 1, 342, 47, 110, '2026-04-03 10:40:00', '2026-04-03 10:40:00', '2026-04-03 10:40:00', 0),
(11, 'RES-GKK-20260403-0003', '小学英语公开课通用模板包', 'english-open-class-template-kit', 4, 2, '适合小学英语公开课、展示课和教研活动使用的课件模板资料。', 'https://placehold.co/1200x760/png?text=resource-11-cover', 59.00, '三年级-六年级', '公开课', '["英语公开课PPT模板","Warm-up页面","单词句型练习页","互动游戏页","说课提纲"]', '<p>这套资料围绕小学英语公开课常见流程设计，适合课堂导入、词句练习、活动互动和课堂总结等环节。</p><p>页面表达清晰，适合老师快速替换课题内容，用于展示课、教研课和赛课准备。</p>', '建议根据学生年级调整英文指令复杂度，并提前检查音频、图片等课堂素材是否齐全。', '本站不做站内支付，确认需求后通过微信沟通交付；建议复制资源码后添加微信。', '英语,公开课,展示课,模板,互动游戏,课件', 'APPROVED', 3, 5, 1, 1, 337, 44, 108, '2026-04-03 10:50:00', '2026-04-03 10:50:00', '2026-04-03 10:50:00', 0),
(12, 'RES-BZR-20260403-0002', '小学班主任期末评语与家校沟通资料包', 'head-teacher-comment-home-school-kit', 1, 1, '适合期末阶段整理学生评语、沟通模板和家校反馈话术的班主任资料包。', 'https://placehold.co/1200x760/png?text=resource-12-cover', 42.00, '一年级-六年级', '家校沟通', '["期末评语模板","家校沟通话术","通知模板","学生表现记录表","沟通建议清单"]', '<p>资料适合班主任在期末集中整理评语和沟通信息时使用，帮助老师提高表达效率并保持整体语气稳妥。</p><p>内容包含可编辑评语模板、沟通话术和家校反馈建议，适合一线班主任高强度期末工作使用。</p>', '建议老师结合学生平时表现先做分类，再从模板中选取合适表述，避免整班语言完全雷同。', '本站不做在线支付，确认需求后通过微信沟通交付；请先看预览，再发送资源码咨询。', '班主任,期末评语,家校沟通,通知模板,沟通话术,资料包', 'APPROVED', 3, 5, 1, 0, 294, 28, 106, '2026-04-03 11:00:00', '2026-04-03 11:00:00', '2026-04-03 11:00:00', 0),
(13, 'RES-JRZ-20260403-0001', '六一儿童节活动主持与班会课件包', 'children-day-activity-class-kit', 6, 1, '适合六一儿童节班会、活动主持、节目串场和氛围展示的资料包。', 'https://placehold.co/1200x760/png?text=resource-13-cover', 35.00, '一年级-六年级', '节日活动', '["六一活动PPT","主持词","节目串场文案","班会活动流程","节日祝福页"]', '<p>这套资料适合六一儿童节前后的班级活动和校园小型庆祝活动，兼顾班会展示和主持串场需要。</p><p>资料内容注重轻松、整洁和节日氛围，便于老师直接套用并替换班级节目安排。</p>', '建议根据活动时长保留核心页面，若有节目单和学生照片，可在封面和流程页中补充展示。', '本站不做在线支付，确认需求后通过微信沟通交付；节日资料建议提前咨询，便于及时安排。', '六一,儿童节,节日活动,主持词,班会,课件', 'APPROVED', 3, 5, 1, 1, 205, 18, 104, '2026-04-03 11:10:00', '2026-04-03 11:10:00', '2026-04-03 11:10:00', 0),
(14, 'RES-FXK-20260403-0002', '小学期末复习冲刺资料整合包', 'final-review-sprint-kit', 5, 3, '适合期末总复习阶段使用的复习清单、课堂展示和家长配合资料整合包。', 'https://placehold.co/1200x760/png?text=resource-14-cover', 52.00, '三年级-六年级', '期末复习', '["期末冲刺PPT","复习计划清单","家长提醒页","课堂展示模板","阶段目标页"]', '<p>这是一套面向期末冲刺阶段的复习资料整合包，目前来源仍在审核中，暂不对前台展示。</p><p>后台可继续补充预览、标签和说明，待授权通过后再发布。</p>', '当前为导入待审核资料，请先补充来源证明和适用年级说明。', '本站不做在线支付。由于该资料来源待审核，当前仅后台可见，不允许前台展示。', '期末,复习,冲刺,家长提醒,阶段目标,整合包', 'PENDING', 2, 5, 0, 0, 34, 0, 90, NULL, '2026-04-03 11:20:00', '2026-04-03 11:20:00', 0),
(15, 'RES-BZR-20260403-0003', '小学班级常规管理模板资料包', 'class-routine-management-template-kit', 1, 4, '适合班主任整理班级公约、值日安排、常规提醒和班级展示内容的模板资料包。', 'https://placehold.co/1200x760/png?text=resource-15-cover', 38.00, '一年级-六年级', '班级管理', '["班级公约模板","值日安排表","课堂常规提醒页","班级展示页","家校通知模板"]', '<p>这套资料已完成基础导入，但来源存在风险待定问题，当前仅后台可见，不允许前台展示。</p><p>若后续来源核验通过，可继续补全预览和文案再发布。</p>', '当前为风险待定资料，请先完成来源核验和授权说明。', '本站不做在线支付。由于来源风险待定，当前仅可用于后台整理和审核。', '班级管理,班主任,常规管理,值日安排,班级公约,模板', 'RISK', 2, 5, 0, 0, 18, 0, 80, NULL, '2026-04-03 11:30:00', '2026-04-03 11:30:00', 0);
