INSERT INTO `page_content` (`id`, `page_code`, `title`, `content_html`, `created_at`, `updated_at`) VALUES
(1, 'about', '关于我们', '<p>我们是一家专注于小学教学场景的备课资料整理站，服务对象主要是一线小学老师、班主任和教研使用者。</p><p>我们提供的不是零散单个文件，而是围绕高频教学场景整理的完整备课资料包，帮助老师更快完成备课准备。</p><p>本站坚持先看预览、再加微信咨询，尽量让老师在有限时间里更快判断资料是否适合自己的年级和场景。</p>', '2026-04-03 08:30:00', '2026-04-03 08:30:00'),
(2, 'contact', '联系我们', '<p>如果您想咨询具体资源内容、适用年级、是否可编辑或交付方式，欢迎通过页面中的微信入口联系我们。</p><p>联系微信：teacherziyuan001</p><p>联系电话：400-820-2026</p><p>联系邮箱：service@teacher-resource.local</p><p>为提高沟通效率，建议您在咨询时直接说明资源码、使用年级和预期课堂场景。</p>', '2026-04-03 08:30:00', '2026-04-03 08:30:00'),
(3, 'disclaimer', '版权与免责声明', '<p>本站展示内容仅用于小学教学备课资料展示与咨询说明，具体交付内容请以微信沟通确认结果为准。</p><p>本站不做在线支付，老师可先查看预览样张，确认资料适用场景后再通过微信沟通交付。</p><p>部分页面示意图仅用于展示资源结构，不代表最终交付中的全部页数和样式。老师在使用资料前，请根据学校要求和班级特点进行必要调整。</p>', '2026-04-03 08:30:00', '2026-04-03 08:30:00'),
(4, 'refund-policy', '退款与补发说明', '<p>本站不提供站内支付，资源交易在微信沟通确认后完成。因资料属于数字内容，请在咨询前先查看预览并确认适用场景。</p><p>若因文件损坏、发送失败或历史订单资料遗失，可联系微信进行补发处理。咨询时建议同步提供资源码，以便快速匹配和补发。</p><p>如遇交付内容与沟通确认结果明显不符，请在交付后第一时间联系处理，我们会根据实际情况协助更换或补充相关资料。</p>', '2026-04-03 08:30:00', '2026-04-03 08:30:00');
